    }
  ]

  var settings = {
    dots: true,
    infinite: true,
    speed: 500,
    slidesToShow: 4,
    slidesToScroll: 1,
    initialSlide: 0,
    responsive: [
      {
        breakpoint: 1024,
        settings: {
          slidesToShow: 3,
          slidesToScroll: 1,
          infinite: true,
          dots: true
        }
      },
      {
        breakpoint: 768,
        settings: {
          slidesToShow: 2,
          slidesToScroll: 1,
          infinite: true,
          dots: true
        }
      },
      {
        breakpoint: 500,
        settings: {
          slidesToShow: 1,
          slidesToScroll: 1,
        }
      }
    ]
  };

  return (
    <div className='blog-items-preview'>
      <h2 className='title'>Delve into Our Latest Articles and Discover New Perspectives</h2>
      <Slider {...settings}>
        {services.map((service, index) => (
          <div className='blog-items-container-outer' key={index}>
            <div className='blog-items-container-inner'>
              <img src={service.img} alt="test" />
              <h2>{service.title}</h2>
              <p>{service.discription}</p>
              <Link to="/blogs">Go To Blogs</Link>
            </div>
          </div>
        ))}
      </Slider>
    </div>
  );
};

export default BlogItemsPreview;
